<span class="line"><span style="color:#89B4FA;font-style:italic;">        assert!</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">matches!</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">result</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Err</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">ProviderError</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">RateLimited</span><span style="color:#9399B2;">)));</span></span>
